import{_ as e,o as a,c as s,ah as o}from"./chunks/framework.C8Zd3T50.js";const u=JSON.parse('{"title":"What About…?","description":"","frontmatter":{},"headers":[],"relativePath":"whatabout/index.md","filePath":"whatabout/index.md"}'),i={name:"whatabout/index.md"};function n(r,t,d,p,l,c){return a(),s("div",null,[...t[0]||(t[0]=[o('<h1 id="what-about" tabindex="-1">What About…? <a class="header-anchor" href="#what-about" aria-label="Permalink to &quot;What About…?&quot;">​</a></h1><div class="tip custom-block"><p class="custom-block-title">A note on this section</p><p>The comparison pages in this section were written mostly by Claude, based on reading all os384 documentation and then researching each alternative system. They were reviewed and edited by /psm but should be understood as AI-generated analysis, not as the personal opinions of the os384 team about any specific project or person.</p></div><p>Anyone working on a genuinely new approach to privacy, security, and data sovereignty will inevitably face the question: &quot;But what about X?&quot; Signal, Matrix, Telegram, Proton — the list is long, and each project has its own community of advocates who believe the problem is already solved.</p><p>We respect the effort behind all of these projects. Many of them have advanced the conversation, and some have made real contributions to the state of the art. But when we apply the criteria laid out in the <a href="/BhoW6b/background.html">Background</a> — AGPL licensing for all components, interoperability, user control, vendor independence, genuine privacy (not just encryption), security, and compatibility with legal oversight — none of them meet the bar. Not one.</p><p>This section examines each of the most commonly cited alternatives and explains, specifically and factually, where they fall short. The goal is not to disparage anyone&#39;s work. It is to be precise about the gap that os384 exists to fill.</p><h2 id="the-sovereignty-litmus-test" tabindex="-1">The Sovereignty Litmus Test <a class="header-anchor" href="#the-sovereignty-litmus-test" aria-label="Permalink to &quot;The Sovereignty Litmus Test&quot;">​</a></h2><p>Before diving into individual systems, here is a quick litmus test. If you answer in the &quot;red&quot; on any of these questions, the system is not sovereign computing.</p><table tabindex="0"><thead><tr><th>#</th><th>Question</th><th>Sovereign Answer</th></tr></thead><tbody><tr><td>1</td><td>Does the service ever require a phone number, an email, or show a CAPTCHA?</td><td><strong>No</strong></td></tr><tr><td>2</td><td>For basic/core capabilities, are you forced to use the provider&#39;s servers and apps?</td><td><strong>No</strong></td></tr><tr><td>3</td><td>Is there a fully capable open-source version of all components needed to run the system yourself?</td><td><strong>Yes</strong></td></tr><tr><td>4</td><td>If you save or share data, do you risk losing it if you fail to do something?</td><td><strong>No</strong></td></tr><tr><td>5</td><td>Can the service provider see any of the data you are saving, or see data shared between multiple parties?</td><td><strong>No</strong></td></tr><tr><td>6</td><td>Does the service have an &quot;export my data&quot; feature?</td><td><strong>Yes</strong></td></tr><tr><td>7</td><td>Can an individual, or any group, migrate (including self-hosting) without the service provider even knowing?</td><td><strong>Yes</strong></td></tr><tr><td>8</td><td>Does the service operate entirely within the legal jurisdiction of the US?</td><td><strong>Yes</strong></td></tr></tbody></table><h3 id="how-the-alternatives-score" tabindex="-1">How the Alternatives Score <a class="header-anchor" href="#how-the-alternatives-score" aria-label="Permalink to &quot;How the Alternatives Score&quot;">​</a></h3><p><em>Hover over any ❌ or ⚠️ for details.</em></p><table class="litmus-table"><thead><tr><th>System</th><th>1</th><th>2</th><th>3</th><th>4</th><th>5</th><th>6</th><th>7</th><th>8</th></tr></thead><tbody><tr><td><strong>os384</strong></td><td>✅</td><td>✅</td><td>✅</td><td>✅</td><td>✅</td><td>✅</td><td>✅</td><td>✅</td></tr><tr><td><a href="/whatabout/signal">Signal</a></td><td><span class="tip" data-tip="Requires a phone number to register. Your identity IS your phone number.">❌</span></td><td><span class="tip" data-tip="All messages route through Signal&#39;s central servers. No third-party servers allowed.">❌</span></td><td><span class="tip" data-tip="Server went dark Apr 2020–Apr 2021. Anti-spam system is proprietary. Development not truly in the open.">❌</span></td><td><span class="tip" data-tip="No data export. If you lose your device, your message history is gone.">❌</span></td><td>✅</td><td><span class="tip" data-tip="No export feature. Messages are device-bound with no extraction mechanism.">❌</span></td><td><span class="tip" data-tip="Impossible. All traffic goes through Signal&#39;s servers. No federation, no self-hosting.">❌</span></td><td>✅</td></tr><tr><td><a href="/whatabout/matrix">Matrix</a></td><td>✅</td><td>✅</td><td><span class="tip" data-tip="Switched to AGPL in Dec 2023 — good. But Synapse server is complex (Python + PostgreSQL) and practical self-hosting requires significant ops expertise.">⚠️</span></td><td><span class="tip" data-tip="Identity is bound to your homeserver (@user:server.tld). If the server disappears, your identity and history go with it.">❌</span></td><td><span class="tip" data-tip="E2E is now on by default, but metadata (who talks to whom, when, room membership) is visible to every federated homeserver operator in the conversation.">⚠️</span></td><td><span class="tip" data-tip="Some export capability exists but it&#39;s inconsistent across clients and not a first-class feature.">⚠️</span></td><td><span class="tip" data-tip="Your identity is permanently bound to your homeserver domain. Migration requires abandoning your identity.">❌</span></td><td><span class="tip" data-tip="Matrix.org Foundation is a UK non-profit. Jurisdiction depends on which homeserver you use.">⚠️</span></td></tr><tr><td><a href="/whatabout/telegram">Telegram</a></td><td><span class="tip" data-tip="Requires a phone number. No alternative registration method.">❌</span></td><td><span class="tip" data-tip="All messages go through Telegram&#39;s servers. No federation, no third-party servers.">❌</span></td><td><span class="tip" data-tip="Server is completely closed source. Client is open source but the MTProto protocol is homegrown with known vulnerabilities.">❌</span></td><td><span class="tip" data-tip="Data lives on Telegram&#39;s servers. If your account is banned or deleted, everything is gone.">❌</span></td><td><span class="tip" data-tip="E2E encryption is opt-in and only for 1:1 &#39;secret chats.&#39; Group chats are NEVER end-to-end encrypted. Telegram can read all group messages.">❌</span></td><td><span class="tip" data-tip="No meaningful data export for server-side content. Limited chat export in desktop client.">❌</span></td><td><span class="tip" data-tip="Impossible. Fully centralized, no federation, no self-hosting option.">❌</span></td><td><span class="tip" data-tip="Headquartered in Dubai. Durov arrested in France (Aug 2024). Multi-jurisdictional legal exposure.">❌</span></td></tr><tr><td><a href="/whatabout/proton">Proton</a></td><td><span class="tip" data-tip="No phone number required, but may require CAPTCHA or email verification during signup. Truly anonymous registration is not guaranteed.">⚠️</span></td><td><span class="tip" data-tip="You must use Proton&#39;s servers. No federation of the encrypted layer. No self-hosting option.">❌</span></td><td><span class="tip" data-tip="Clients are open source, but the server is completely proprietary and closed.">❌</span></td><td><span class="tip" data-tip="Data lives on Proton&#39;s servers. If your account is closed, data is lost.">❌</span></td><td><span class="tip" data-tip="E2E encryption for Proton-to-Proton email, but email headers (sender, recipient, subject, timestamps) are always in cleartext. Non-Proton email is not E2E.">⚠️</span></td><td><span class="tip" data-tip="Some export tools exist but they&#39;re limited and don&#39;t cover all products equally.">⚠️</span></td><td><span class="tip" data-tip="Impossible. Single provider, no federation, no way to self-host Proton&#39;s infrastructure.">❌</span></td><td><span class="tip" data-tip="Swiss jurisdiction. Strong privacy law, but laws change — Proton is already moving infrastructure due to proposed Swiss surveillance legislation.">❌</span></td></tr><tr><td><a href="/whatabout/whatsapp">WhatsApp</a></td><td><span class="tip" data-tip="Requires a phone number. Your WhatsApp identity IS your phone number.">❌</span></td><td><span class="tip" data-tip="Completely walled garden. Meta&#39;s servers and apps only. No third-party clients allowed.">❌</span></td><td><span class="tip" data-tip="Both client and server are completely closed source. No way to verify the Signal Protocol implementation.">❌</span></td><td><span class="tip" data-tip="Unencrypted cloud backups were the default for years. Account ban means losing everything.">❌</span></td><td><span class="tip" data-tip="Message content is E2E encrypted, but Meta collects extensive metadata: contacts, usage patterns, device info, location — and shares it with Facebook for ad targeting.">❌</span></td><td><span class="tip" data-tip="No meaningful export feature. Chat export produces limited text files with no media fidelity.">❌</span></td><td><span class="tip" data-tip="Impossible. Fully centralized Meta infrastructure. No federation, no interop (DMA compliance is minimal).">❌</span></td><td>✅</td></tr><tr><td><a href="/whatabout/ipfs">IPFS</a></td><td>✅</td><td>✅</td><td>✅</td><td><span class="tip" data-tip="Data persists only as long as at least one node pins it. No automatic persistence guarantee — if no one pins your content, it&#39;s garbage-collected.">⚠️</span></td><td><span class="tip" data-tip="All data stored in cleartext. The DHT is a public record of who requests what. Your IP address is visible to other nodes.">❌</span></td><td><span class="tip" data-tip="Not applicable — IPFS is a protocol, not a service. You already have your data if you&#39;re running a node.">N/A</span></td><td>✅</td><td><span class="tip" data-tip="Protocol Labs is a US company, but IPFS is a protocol — jurisdiction depends on individual node operators.">⚠️</span></td></tr><tr><td><a href="/whatabout/nextcloud">Nextcloud</a></td><td>✅</td><td>✅</td><td>✅</td><td><span class="tip" data-tip="Self-hosted instances depend on the operator maintaining the server. No built-in redundancy or automatic data preservation.">❌</span></td><td><span class="tip" data-tip="Server-side encryption exists but the server holds the keys. E2E encryption module is optional, limited to specific folders, and not enabled by default.">❌</span></td><td>✅</td><td><span class="tip" data-tip="Identity is server-bound. No portable cryptographic identity. Migration requires admin cooperation or starting over.">❌</span></td><td><span class="tip" data-tip="German company (Nextcloud GmbH), but since it&#39;s self-hosted, jurisdiction depends on where you run it.">⚠️</span></td></tr><tr><td><a href="/whatabout/solid">Solid</a></td><td>✅</td><td><span class="tip" data-tip="You need a pod provider or must self-host a pod server. The ecosystem of Solid-compatible apps is very small.">⚠️</span></td><td>✅</td><td><span class="tip" data-tip="Pod depends on hosting infrastructure. If the pod provider shuts down, data is at risk unless you&#39;ve backed it up.">❌</span></td><td><span class="tip" data-tip="Pods store data in cleartext. The server (or hosting provider) can read everything. Access control is server-side ACLs, not cryptography.">❌</span></td><td>✅</td><td><span class="tip" data-tip="Identity (WebID) is tied to a URL on a specific server. If that server goes down, your identity is unresolvable.">❌</span></td><td><span class="tip" data-tip="Inrupt (commercial entity) is US-based. W3C governance is international. Pod jurisdiction depends on hosting.">⚠️</span></td></tr><tr><td><a href="/whatabout/keybase">Keybase</a></td><td>✅</td><td><span class="tip" data-tip="All services depend on Keybase&#39;s (now Zoom&#39;s) central infrastructure. No federation, no self-hosting.">❌</span></td><td><span class="tip" data-tip="Client was open source but server was always proprietary. Since Zoom acquisition, development has effectively stopped.">❌</span></td><td><span class="tip" data-tip="Service is in maintenance mode since Zoom acquisition. No new signups. Users have no migration path if it shuts down.">❌</span></td><td>✅</td><td><span class="tip" data-tip="No data export mechanism. Your identity proofs, files, and chat history are locked in Keybase&#39;s infrastructure.">❌</span></td><td><span class="tip" data-tip="Impossible. Fully centralized. The Zoom acquisition proved the point — users had zero recourse.">❌</span></td><td>✅</td></tr><tr><td><a href="/whatabout/session">Session</a></td><td>✅</td><td><span class="tip" data-tip="Uses a decentralized service node network (good), but the network depends on Oxen blockchain token staking. You can&#39;t run a basic node without cryptocurrency.">⚠️</span></td><td><span class="tip" data-tip="Client is open source (GPL). But the service node network depends on the Oxen blockchain, and the overall system&#39;s auditability is limited by blockchain complexity.">⚠️</span></td><td><span class="tip" data-tip="Messages are routed through service nodes with limited persistence. No reliable long-term storage guarantee.">❌</span></td><td>✅</td><td><span class="tip" data-tip="No data export feature. Messages are ephemeral in the network and device-bound.">❌</span></td><td><span class="tip" data-tip="You can&#39;t migrate without the Oxen service node network. The infrastructure is decentralized but not separable.">❌</span></td><td><span class="tip" data-tip="Oxen/Session is developed by OPTF, an Australian non-profit. Blockchain nodes are globally distributed but governance is not US-based.">❌</span></td></tr></tbody></table><p>✅ = passes, ❌ = fails, ⚠️ = partial/qualified</p><h2 id="the-criteria" tabindex="-1">The Criteria <a class="header-anchor" href="#the-criteria" aria-label="Permalink to &quot;The Criteria&quot;">​</a></h2><p>For reference, these are the requirements from the <a href="/BhoW6b/background.html#criteria-for-a-real-solution">Background</a> that we apply to each system:</p><ol><li><strong>AGPL open source</strong> — all components, server and client, under Affero-style licensing with development done in the open.</li><li><strong>Interoperable</strong> — open to connecting to other instances following open standards or well-documented protocols.</li><li><strong>User control</strong> — any user can leave and retain all their data.</li><li><strong>Vendor independent</strong> — no artificial lock-ins.</li><li><strong>Truly private</strong> — no PII required by the protocol; no metadata leakage; no phone number, email, or identity requirement.</li><li><strong>Secure</strong> — end-to-end encryption that doesn&#39;t depend on trusting the provider.</li><li><strong>Compatible with responsible legal oversight.</strong></li></ol><p>Additionally, we consider:</p><ul><li><strong>App delivery trust</strong> — can the user verify that the code running on their device is what it claims to be?</li><li><strong>Self-hostable in practice</strong> — not just theoretically possible, but simple enough that a small team or individual can actually do it.</li></ul><h2 id="the-comparisons" tabindex="-1">The Comparisons <a class="header-anchor" href="#the-comparisons" aria-label="Permalink to &quot;The Comparisons&quot;">​</a></h2><ul><li><a href="/BhoW6b/whatabout/signal.html">Signal</a> — E2E encryption poster child, but centralized, phone-number-dependent, and not as open as it appears.</li><li><a href="/BhoW6b/whatabout/matrix.html">Matrix / Element</a> — the most serious federated protocol, but complex, metadata-leaking, and cryptographically troubled.</li><li><a href="/BhoW6b/whatabout/telegram.html">Telegram</a> — massive user base, but encryption is opt-in, the server is closed, and the crypto is homegrown.</li><li><a href="/BhoW6b/whatabout/proton.html">Proton</a> — Swiss privacy branding with closed servers and the fundamental limitations of email.</li><li><a href="/BhoW6b/whatabout/whatsapp.html">WhatsApp</a> — good crypto inside a surveillance business model.</li><li><a href="/BhoW6b/whatabout/ipfs.html">IPFS</a> — content-addressed and philosophically adjacent, but no encryption and no privacy.</li><li><a href="/BhoW6b/whatabout/nextcloud.html">Nextcloud</a> — self-hosted collaboration done right in some ways, but encryption is an afterthought.</li><li><a href="/BhoW6b/whatabout/solid.html">Solid</a> — Berners-Lee&#39;s re-decentralization effort, but layered on top of the wrong foundation.</li><li><a href="/BhoW6b/whatabout/keybase.html">Keybase</a> — crypto identity done well, then acquired by Zoom. A cautionary tale.</li><li><a href="/BhoW6b/whatabout/session.html">Session</a> — a Signal fork that removed the phone number, but introduced a blockchain.</li></ul>',19)])])}const m=e(i,[["render",n]]);export{u as __pageData,m as default};
